import React, { createContext, useContext, useState, useCallback, useRef } from 'react';

const ToastContext = createContext();

export const ToastProvider = ({ children }) => {
  const [toasts, setToasts] = useState([]);
  const timers = useRef({}); // Prevents memory leaks by tracking active timers

  const removeToast = useCallback((id) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
    if (timers.current[id]) {
      clearTimeout(timers.current[id]);
      delete timers.current[id];
    }
  }, []);

  const addToast = useCallback((message, type = 'info') => {
    const id = Math.random().toString(36).substr(2, 9);
    
    setToasts((prev) => [...prev, { id, message, type }]);

    // Auto-clear toast after 4 seconds
    timers.current[id] = setTimeout(() => {
      removeToast(id);
    }, 4000);
  }, [removeToast]);

  return (
    <ToastContext.Provider value={addToast}>
      {children}
      
      {/* Toast Container Stack */}
      <div className="fixed bottom-6 right-6 z-[9999] flex flex-col gap-3 font-mono">
        {toasts.map((t) => (
          <div 
            key={t.id} 
            onClick={() => removeToast(t.id)}
            className={`cursor-pointer px-5 py-3 border text-[11px] shadow-2xl transition-all animate-in slide-in-from-right-5
              ${t.type === 'error' 
                ? 'bg-[#1a1a1a] border-red-500/40 text-red-400' 
                : 'bg-[#1a1a1a] border-emerald-500/40 text-emerald-400'
              }`}
          >
            <span className="opacity-40 mr-2">
              {t.type === 'error' ? '[!]' : '[*]'}
            </span>
            {t.message.toUpperCase()}
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
};

export const useToast = () => {
  const context = useContext(ToastContext);
  if (!context) throw new Error("useToast must be used within ToastProvider");
  return context;
};
